SELECT con_id, name, open_mode, restricted, total_size
FROM v$pdbs
ORDER BY con_id;

SELECT pdb_name, con_id, status, creation_scn, con_uid
FROM cdb_pdbs
ORDER BY con_id;

-- PDB를 READ WRITE로 오픈
ALTER PLUGGABLE DATABASE pdb1 OPEN;

-- PDB를 READ ONLY로 오픈
ALTER PLUGGABLE DATABASE pdb1 OPEN READ ONLY;

-- PDB를 RESTRICTED 모드로 오픈
ALTER PLUGGABLE DATABASE pdb1 OPEN READ WRITE RESTRICTED;

-- PDB를 FORCE로 모드 전환 (CLOSE 없이)
ALTER PLUGGABLE DATABASE pdb1 OPEN READ WRITE FORCE;

-- PDB 닫기 (MOUNTED 상태로 전환)
ALTER PLUGGABLE DATABASE pdb1 CLOSE IMMEDIATE;

-- 모든 PDB 오픈
ALTER PLUGGABLE DATABASE ALL OPEN;

-- 현재 PDB의 오픈 상태 저장
ALTER PLUGGABLE DATABASE pdb1 SAVE STATE;

-- 모든 PDB의 오픈 상태 저장
ALTER PLUGGABLE DATABASE ALL SAVE STATE;

-- 특정 PDB를 제외하고 상태 저장
ALTER PLUGGABLE DATABASE ALL EXCEPT pdb_seed SAVE STATE;

-- 저장된 상태 삭제 (DISCARD)
ALTER PLUGGABLE DATABASE pdb1 DISCARD STATE;

-- 모든 PDB의 저장된 상태 삭제
ALTER PLUGGABLE DATABASE ALL DISCARD STATE;

-- 1. PDB 닫기
ALTER PLUGGABLE DATABASE pdb1 CLOSE IMMEDIATE;

-- 2. PDB Unplug (XML 메타데이터)
ALTER PLUGGABLE DATABASE pdb1
  UNPLUG INTO '/u01/app/oracle/pdb1.xml';

-- 1. PDB 닫기
ALTER PLUGGABLE DATABASE pdb1 CLOSE IMMEDIATE;

-- 2. PDB Unplug (단일 아카이브)
ALTER PLUGGABLE DATABASE pdb1
  UNPLUG INTO '/u01/app/oracle/pdb1.pdb';

-- UNPLUGGED 상태 확인
SELECT pdb_name, status
FROM cdb_pdbs
WHERE status = 'UNPLUGGED';

-- UNPLUGGED PDB 삭제 (데이터 파일 유지)
DROP PLUGGABLE DATABASE pdb1 KEEP DATAFILES;

SET SERVEROUTPUT ON
DECLARE
  l_result BOOLEAN;
BEGIN
  l_result := DBMS_PDB.CHECK_PLUG_COMPATIBILITY(
    pdb_descr_file => '/u01/app/oracle/pdb1.xml',
    pdb_name       => 'PDB1_NEW'
  );
  IF l_result THEN
    DBMS_OUTPUT.PUT_LINE('Compatible - Plug In possible');
  ELSE
    DBMS_OUTPUT.PUT_LINE('Not compatible - Check PDB_PLUG_IN_VIOLATIONS');
  END IF;
END;
/

-- 데이터 파일 포함 완전 삭제
DROP PLUGGABLE DATABASE pdb1 INCLUDING DATAFILES;

-- 데이터 파일 유지 삭제
DROP PLUGGABLE DATABASE pdb1 KEEP DATAFILES;

-- [원본 CDB에서]
-- 1. PDB 닫기
ALTER PLUGGABLE DATABASE pdb1 CLOSE IMMEDIATE;

-- 2. Unplug
ALTER PLUGGABLE DATABASE pdb1
  UNPLUG INTO '/u01/app/oracle/pdb1.pdb';

-- 3. DROP (데이터 파일 유지 불필요 — .pdb에 포함됨)
DROP PLUGGABLE DATABASE pdb1 INCLUDING DATAFILES;

-- [대상 CDB에서]
-- 4. 호환성 검사 후 Plug In
CREATE PLUGGABLE DATABASE pdb1
  USING '/u01/app/oracle/pdb1.pdb';

-- 5. PDB 오픈
ALTER PLUGGABLE DATABASE pdb1 OPEN;

-- 6. 상태 저장
ALTER PLUGGABLE DATABASE pdb1 SAVE STATE;
